            action: AutomaticAnswerAction,
            col: Collection,
            selectedDid: DeckId
        ): AutomaticAnswerSettings? {
            // New backend (23.12) has auto advance settings in the deck config itself
            val deckConf = col.decks.confForDid(selectedDid)

            val waitQuestionSeconds = deckConf.optInt("secondsToShowQuestion", 0)
            val waitAnswerSeconds = deckConf.optInt("secondsToShowAnswer", 0)
            val answerActionIdx = deckConf.optInt("answerAction", 0)

            val useTimer = waitQuestionSeconds > 0 || waitAnswerSeconds > 0

            // If we have valid settings from the deck config, use them.
            // Even if useTimer is false (both 0), we return the settings object which will result in disabled auto-advance,
            // effectively taking precedence over global preferences (which is the intended behavior for 23.12 update).

            // However, to be safe and strictly follow "switch to using the settings in the current card's deck options",
            // we should probably just return the object derived from deck config.

            val answerAction = AutomaticAnswerAction.fromPreferenceValue(answerActionIdx)

            return AutomaticAnswerSettings(answerAction, useTimer, waitQuestionSeconds, waitAnswerSeconds)
        }","old_string":"        fun queryDeckSpecificOptions(
            action: AutomaticAnswerAction,
            col: Collection,
            selectedDid: DeckId
        ): AutomaticAnswerSettings? {
            // Dynamic don't have review options; attempt to get deck-specific auto-advance options
            // but be prepared to go with all default if it's a dynamic deck
            if (col.decks.isDyn(selectedDid)) {
                return null
            }

            val revOptions = col.decks.confForDid(selectedDid).getJSONObject("rev")

            if (revOptions.optBoolean("useGeneralTimeoutSettings", true)) {
                // we want to use the general settings, no need for per-deck settings
                return null
            }

            val useTimer = revOptions.optBoolean("timeoutAnswer", false)
            val waitQuestionSecond = revOptions.optInt("timeoutQuestionSeconds", 60)
            val waitAnswerSecond = revOptions.optInt("timeoutAnswerSeconds", 20)
            return AutomaticAnswerSettings(action, useTimer, waitQuestionSecond, waitAnswerSecond)
        }"}

